import{_ as t,o as a,c as o,a3 as n}from"./chunks/framework.BveOjhN0.js";const h=JSON.parse('{"title":"Payment Gateways — Production Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Payment Gateways — Production Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/deployment/payment-gateways"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Payment Gateways — Production Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/deployment/payment-gateways"}]]},"headers":[],"relativePath":"deployment/payment-gateways.md","filePath":"deployment/payment-gateways.md","lastUpdated":1784076469000}'),r={name:"deployment/payment-gateways.md"};function s(i,e,d,c,l,p){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="payment-gateways-—-production-guide" tabindex="-1">Payment Gateways — Production Guide <a class="header-anchor" href="#payment-gateways-—-production-guide" aria-label="Permalink to &quot;Payment Gateways — Production Guide&quot;">​</a></h1><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ol><li>Seed gateways: <code>PaymentGatewaySeeder</code> (manual + stripe).</li><li>In Central UI, configure Stripe <strong>live</strong> credentials (or set encrypted config via API).</li><li>Set Stripe as default only after a successful <strong>Test connection</strong>.</li><li>Register webhooks in the Stripe Dashboard: <ul><li>Prefer <code>https://{APP_URL}/stripe/webhook</code> for Cashier subscription mirror + Billing Engine</li><li>Or <code>https://{APP_URL}/webhooks/gateways/stripe</code> for Billing Engine only</li></ul></li><li>Store the webhook signing secret in gateway config (<code>webhook_secret</code>) and/or <code>STRIPE_WEBHOOK_SECRET</code> for Cashier middleware.</li><li>Confirm CSRF exclusions remain for <code>stripe/*</code> and <code>webhooks/gateways/*</code>.</li><li>Monitor <strong>webhook status</strong> and <code>webhook_logs</code> after go-live.</li></ol><h2 id="environment-fallbacks" tabindex="-1">Environment fallbacks <a class="header-anchor" href="#environment-fallbacks" aria-label="Permalink to &quot;Environment fallbacks&quot;">​</a></h2><p><code>StripeGateway</code> prefers encrypted <code>payment_gateways.config.secret_key</code>. If absent, it falls back to Cashier env (<code>STRIPE_SECRET</code>). Production should treat DB-encrypted credentials as source of truth so credentials can rotate without redeploying env.</p><h2 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h2><ul><li>Never log secret values — only changed key names.</li><li>Never return secrets from API resources.</li><li>Prefer sandbox mode until connection tests pass.</li><li>Rotate webhook secrets after any suspected leak; update both Stripe Dashboard and gateway config.</li></ul><h2 id="ops-signals" tabindex="-1">Ops signals <a class="header-anchor" href="#ops-signals" aria-label="Permalink to &quot;Ops signals&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Signal</th><th>Source</th></tr></thead><tbody><tr><td><code>payment_gateways.webhook_status</code></td><td><code>ok</code> / <code>failing</code> / <code>unknown</code></td></tr><tr><td><code>webhook_last_received_at</code></td><td>Last successful ingress</td></tr><tr><td><code>gateway_logs</code></td><td>Config/mode/test events</td></tr><tr><td><code>webhook_logs</code></td><td>Per-event processing result + timing</td></tr></tbody></table>',9)])])}const g=t(r,[["render",s]]);export{h as __pageData,g as default};
